def _utcnow() -> str: return datetime.now(timezone.utc).isoformat()
def _raw(env: Mapping[str,str], name: str) -> Optional[str]:
    v=env.get(name)
    return None if v is None else str(v).strip()
def _bool(env: Mapping[str,str], name: str, default: bool=False) -> tuple[bool, Optional[str]]:
    v=_raw(env,name)
    if v is None or v=="": return default,None
    x=v.lower()
    if x in _TRUE:return True,None
    if x in _FALSE:return False,None
    return default,f"{name} must be a boolean (true/false)."
def _configured(env: Mapping[str,str], name: str) -> bool: return bool(_raw(env,name))
def _issue(level:str, code:str, message:str, variable:Optional[str]=None)->Dict[str,Any]:
    return {"level":level,"code":code,"variable":variable,"message":message}

def execution_safety(env: Optional[Mapping[str,str]]=None) -> Dict[str,Any]:
    env=env or os.environ
    broker_env=(_raw(env,"ETRADE_ENV") or "sandbox").lower()
    global_enabled, global_err=_bool(env,"ETRADE_ENABLE_TRADING",False)
    confirmation_gate, conf_err=_bool(env,"APEX_CONFIRMATION_GATED_EXECUTION_ENABLED",False)
    creds=["ETRADE_CONSUMER_KEY","ETRADE_CONSUMER_SECRET","ETRADE_OAUTH_TOKEN","ETRADE_OAUTH_TOKEN_SECRET","ETRADE_ACCOUNT_ID_KEY"]
    broker_configured=all(_configured(env,n) for n in creds)
    human_confirmation_required=True
    automatic_execution_enabled=False
    live_mode=broker_env in {"production","live"}
    paper_mode=not live_mode
    broker_mutation_enabled=bool(global_enabled and confirmation_gate)
    blocking=[]; warnings=[]
    if global_err:blocking.append(global_err)
    if conf_err:blocking.append(conf_err)
    if global_enabled and not broker_configured:blocking.append("Broker submission is enabled without complete E*TRADE credentials.")
    if global_enabled and not confirmation_gate:blocking.append("Global trading is enabled but confirmation-gated broker mutation is disabled.")
    if broker_mutation_enabled and broker_env=="sandbox" and (_raw(env,"APEX_ENVIRONMENT") or "").lower() in {"production","prod","live"}:
        blocking.append("Production execution is enabled while ETRADE_ENV is sandbox.")
    if confirmation_gate and not global_enabled:warnings.append("Confirmation-gated execution is armed, but the authoritative ETRADE_ENABLE_TRADING kill switch remains off.")
    if live_mode and not global_enabled:warnings.append("Live broker environment selected while the authoritative trading kill switch is off.")
    safe_to_preview=broker_configured
    safe_to_submit=bool(broker_configured and broker_mutation_enabled and human_confirmation_required and not blocking)
    return {"broker_configured":broker_configured,"broker_environment":broker_env,"global_trading_enabled":global_enabled,
      "automatic_execution_enabled":automatic_execution_enabled,"human_confirmation_required":human_confirmation_required,
      "broker_mutation_enabled":broker_mutation_enabled,"paper_mode":paper_mode,"live_mode":live_mode,
      "safe_to_preview":safe_to_preview,"safe_to_submit":safe_to_submit,"blocking_reasons":blocking,"warnings":warnings,
      "authoritative_kill_switch":"ETRADE_ENABLE_TRADING","evaluated_at":_utcnow()}

def _validate_value(defn:VariableDefinition, value:str)->Optional[str]:
    if defn.expected_type=="boolean" and value.lower() not in _TRUE|_FALSE:return "invalid boolean"
    if defn.expected_type=="integer":
        try:
            if int(value)<0:return "must be non-negative"
        except ValueError:return "invalid integer"
    if defn.expected_type=="number":
        try: float(value)
        except ValueError:return "invalid number"
    if defn.allowed_values and value.lower() not in {str(v).lower() for v in defn.allowed_values}:return "invalid enum value"
    return None

def diagnostics(env: Optional[Mapping[str,str]]=None) -> Dict[str,Any]:
    env=env or os.environ; issues=[]; variables=[]
    for name,defn in REGISTRY.items():
        raw=_raw(env,name); configured=bool(raw)
        if configured:
            err=_validate_value(defn,raw)
            if err:issues.append(_issue("BLOCKING" if defn.safety_critical else "WARNING","INVALID_VALUE",f"{name}: {err}.",name))
            if defn.deprecated:issues.append(_issue("WARNING","DEPRECATED_VARIABLE",f"{name} is deprecated"+(f"; use {defn.replacement}." if defn.replacement else "."),name))
            if not defn.used_in_code:issues.append(_issue("INFO","RECOGNIZED_UNUSED",f"{name} is recognized metadata but is not directly consumed by application code.",name))
        variables.append({**asdict(defn),"configured":configured,"display_value":"[REDACTED]" if defn.secret and configured else (raw if configured else defn.default)})
    safety=execution_safety(env)
    for message in safety["blocking_reasons"]:issues.append(_issue("BLOCKING","EXECUTION_SAFETY",message))
    for message in safety["warnings"]:issues.append(_issue("WARNING","EXECUTION_SAFETY",message))
    webhook_enabled=any((_raw(env,n) or "").lower() in _TRUE for n in ("RUN_SCANNER_ON_IMPORT",))
    if webhook_enabled and not any(_configured(env,n) for n in ("TV_WEBHOOK_SECRET","WEBHOOK_SECRET","TRADINGVIEW_SECRET")):
        issues.append(_issue("BLOCKING","MISSING_WEBHOOK_SECRET","Webhook-capable runtime is enabled without a configured webhook secret.","TV_WEBHOOK_SECRET"))
    for key in sorted(env):
        if key.startswith("APEX_") and key not in REGISTRY:
            issues.append(_issue("WARNING","UNKNOWN_APEX_VARIABLE",f"Unknown APEX-prefixed variable detected: {key}.",key))
    metadata_names=("APEX_BUILD_ID","APEX_RELEASE_NAME","APEX_GIT_COMMIT","APEX_GIT_BRANCH","APEX_DEPLOYED_AT","APEX_DATABASE_SCHEMA_VERSION","APEX_INSTANCE_NAME","APEX_REGION")
    missing_meta=[n for n in metadata_names if not _configured(env,n)]
    if missing_meta:issues.append(_issue("WARNING","OPTIONAL_METADATA_MISSING","Optional deployment metadata is incomplete: "+", ".join(missing_meta)+"."))
    state="BLOCKING" if any(i["level"]=="BLOCKING" for i in issues) else "WARNING" if any(i["level"]=="WARNING" for i in issues) else "INFO" if issues else "PASS"
    release=release_metadata()
    return {"ok":state!="BLOCKING","state":state,"version":APP_VERSION,"evaluated_at":_utcnow(),"issues":issues,"variables":variables,
      "execution_safety":safety,"deployment_identity":release,"derived":{"effective_log_level":(_raw(env,"LOG_LEVEL") or "INFO").upper(),"scanner_enabled":not ((_raw(env,"DISABLE_BACKGROUND_SCANNER") or "false").lower() in _TRUE),"render_metadata_available":any(k.startswith("RENDER_") for k in env)}}

def status(env: Optional[Mapping[str,str]]=None)->Dict[str,Any]:
    d=diagnostics(env); vars=d["variables"]; issues=d["issues"]
    return {"ok":d["ok"],"state":d["state"],"version":APP_VERSION,"configured":sum(1 for v in vars if v["configured"]),
      "missing_required":sum(1 for i in issues if i["code"]=="MISSING_REQUIRED"),"warnings":sum(1 for i in issues if i["level"]=="WARNING"),
      "blocking":sum(1 for i in issues if i["level"]=="BLOCKING"),"deprecated":sum(1 for i in issues if i["code"]=="DEPRECATED_VARIABLE"),
      "unknown":sum(1 for i in issues if i["code"]=="UNKNOWN_APEX_VARIABLE"),"execution_safe":d["execution_safety"]["safe_to_submit"] or not d["execution_safety"]["global_trading_enabled"],
      "evaluated_at":d["evaluated_at"]}

def categories(env: Optional[Mapping[str,str]]=None)->Dict[str,Any]:
    d=diagnostics(env); out=[]
    for cat in CATEGORIES:
        vs=[v for v in d["variables"] if v["category"]==cat]
        if vs:out.append({"category":cat,"total":len(vs),"configured":sum(1 for v in vs if v["configured"]),"secrets":sum(1 for v in vs if v["secret"])})
    return {"ok":True,"version":APP_VERSION,"categories":out,"evaluated_at":d["evaluated_at"]}

def safe_startup_validation(env: Optional[Mapping[str,str]]=None)->Dict[str,Any]:
    result=diagnostics(env)
    # Fail closed at the execution boundary; application observability remains available.
    if result["state"]=="BLOCKING":LOGGER.error("APEX configuration validation found blocking safety issues; broker submission remains fail-closed.")
    elif result["state"]=="WARNING":LOGGER.warning("APEX configuration validation completed with warnings.")
    else:LOGGER.info("APEX configuration validation passed.")
    return result
